function DrawShape({ color, size, type }) {
  const draw = useCallback((g) => {
    g.clear();
    if (type === 'circle') {
      g.circle(0, 0, size / 2);
    } else if (type === 'triangle') {
      const h = size * 0.866;
      g.moveTo(0, -h / 2);
      g.lineTo(size / 2, h / 2);
      g.lineTo(-size / 2, h / 2);
      g.closePath();
    } else {
      g.roundRect(-size / 2, -size / 2, size, size, 4);
    }
    g.fill(color);
  }, [color, size, type]);
  return <graphics draw={draw} />;
}

import { useTick } from '@pixi/react';

function DraggableShape({ id, x, y, color, size, type, speed, onDrop }) {
  const ref = useRef(null);
  const drag = useRef(false);
  const off = useRef({ x: 0, y: 0 });
  const spd = useRef(speed);
  useEffect(() => { spd.current = speed; }, [speed]);

  useTick((t) => {
    if (ref.current && !drag.current) {
      ref.current.rotation += 0.02 * spd.current * t.deltaTime;
    }
  });

  useEffect(() => {
    const c = ref.current;
    if (!c) return;
    c.eventMode = 'static';
    c.cursor = 'grab';

    const down = (e) => {
      drag.current = true;
      c.cursor = 'grabbing';
      c.alpha = 0.75;
      c.scale.set(1.1);
      const p = e.global;
      off.current = { x: p.x - c.x, y: p.y - c.y };
    };
    const move = (e) => {
      if (!drag.current) return;
      const p = e.global;
      c.x = p.x - off.current.x;
      c.y = p.y - off.current.y;
    };
    const up = () => {
      if (!drag.current) return;
      drag.current = false;
      c.cursor = 'grab';
      c.alpha = 1;
      c.scale.set(1);
      onDrop({ id, x: c.x, y: c.y, type, color });
    };

    c.on('pointerdown', down);
    c.on('globalpointermove', move);
    c.on('pointerup', up);
    c.on('pointerupoutside', up);
    return () => {
      c.off('pointerdown', down);
      c.off('globalpointermove', move);
      c.off('pointerup', up);
      c.off('pointerupoutside', up);
    };
  }, [id, type, color, onDrop]);

  return (
    <container ref={ref} x={x} y={y}>
      <DrawShape color={color} size={size} type={type} />
    </container>
  );
}

const ZONE = { x: 650, y: 250, w: 220, h: 420 };

function DropZone() {
  const draw = useCallback((g) => {
    g.clear();
    g.setStrokeStyle({ width: 2, color: 0x3f3f46, alpha: 0.6 });
    g.roundRect(-ZONE.w / 2, -ZONE.h / 2, ZONE.w, ZONE.h, 16);
    g.stroke();
    g.setStrokeStyle({ width: 1, color: 0x22d3ee, alpha: 0.15 });
    g.roundRect(-ZONE.w / 2 + 6, -ZONE.h / 2 + 6, ZONE.w - 12, ZONE.h - 12, 12);
    g.stroke();
  }, []);

  return (
    <container x={ZONE.x} y={ZONE.y}>
      <graphics draw={draw} />
    </container>
  );
}

