import { Container, Graphics } from 'pixi.js';
import { Application, extend } from '@pixi/react';
extend({ Container, Graphics });

const ZONE = { x: 650, y: 250, w: 220, h: 420 };
const TYPES = ['rect', 'circle', 'triangle'];

function App() {
  const { data, send } = useNodeRed();
  const [shapes, setShapes] = useState([]);
  const [dropCount, setDropCount] = useState(0);
  const idRef = useRef(0);

  useEffect(() => {
    if (!data) return;
    const type = data.type || TYPES[Math.floor(Math.random() * TYPES.length)];
    setShapes(prev => {
      const next = [...prev, {
        id: idRef.current++,
        x: 60 + Math.random() * 300,
        y: 60 + Math.random() * 380,
        color: data.color || 0x22d3ee,
        size: data.size || 60,
        speed: data.speed || 1,
        type
      }];
      return next.length > 15 ? next.slice(-15) : next;
    });
  }, [data]);

  const handleDrop = useCallback((info) => {
    const inZone = info.x > ZONE.x - ZONE.w / 2 && info.x < ZONE.x + ZONE.w / 2 &&
                   info.y > ZONE.y - ZONE.h / 2 && info.y < ZONE.y + ZONE.h / 2;
    if (inZone) {
      setShapes(prev => prev.filter(s => s.id !== info.id));
      setDropCount(c => c + 1);
      send({ action: 'dropped', shape: info.type, color: info.color, x: Math.round(info.x), y: Math.round(info.y) }, 'pixi/drop');
    }
  }, [send]);

  const colorHex = data ? '#' + (data.color || 0).toString(16).padStart(6, '0') : '#22d3ee';

  return (
    <Page>
      <Header title="fromcubes Pixi" subtitle="drag shapes into the drop zone" />
      <div className="flex-1 flex items-center justify-center p-6">
        <div className="rounded-xl overflow-hidden border border-zinc-800">
          <Application width={800} height={500} background={0x18181b} antialias>
            <DropZone />
            {shapes.map(s => (
              <DraggableShape key={s.id} {...s} onDrop={handleDrop} />
            ))}
          </Application>
        </div>
      </div>
      <StatusBar count={shapes.length} dropCount={dropCount} colorHex={colorHex} size={data?.size} speed={data?.speed} />
    </Page>
  );
}
